const body = $input.first().json.body || $input.first().json;
const proposal = (body.proposal || '').trim();

if (!proposal || proposal.length < 5) {
  throw new Error('INVALID_PROPOSAL: proposal field missing or too short');
}

return [{ json: { proposal } }];

const proposal = $input.first().json.proposal;
const t = proposal.toLowerCase();

const POLICY = [
  {
    key: 'DESTRUCTIVE',
    keywords: ['drop', 'delete', 'destroy', 'truncate', 'wipe', 'purge', 'remove all', 'nuke', 'terminate all', 'erase'],
    verdict: 'BLOCK',
    class: 'DESTRUCTIVE_ACTION',
    reason: 'Proposal matches a destructive action class. Destructive operations require human authorization and cannot be verified as safe for automated execution.',
    constraints_failed: ['destructive_action_gate', 'requires_human_authorization']
  },
  {
    key: 'UNAUTHORIZED',
    keywords: ['without approval', 'bypass', 'skip review', 'no approval', 'override', 'disable mfa', 'disable security', 'revoke all', 'disable enforcement'],
    verdict: 'BLOCK',
    class: 'POLICY_BYPASS_ATTEMPT',
    reason: 'Proposal contains explicit policy bypass language. Requests to disable controls or skip approval gates are rejected at the execution boundary.',
    constraints_failed: ['policy_bypass_gate', 'authorization_required']
  },
  {
    key: 'HIGH_RISK',
    keywords: ['scale to zero', 'production', 'prod', 'rotate', 'revoke', 'restart all', 'deploy to prod', 'rebuild', 'migrate', 'cutover'],
    verdict: 'CONDITIONAL',
    class: 'HIGH_RISK_OPERATION',
    reason: 'Proposal classified as high-risk. Execution requires verified approval token, change window confirmation, and blast-radius attestation.',
    constraints_failed: []
  },
  {
    key: 'READ_ONLY',
    keywords: ['report', 'list', 'describe', 'show', 'get', 'fetch', 'read', 'query', 'check status', 'audit', 'generate report'],
    verdict: 'ALLOW',
    class: 'READ_ONLY_OPERATION',
    reason: 'Proposal classified as a read-only operation. No execution boundary crossed. Decision sealed for audit trail.',
    constraints_failed: []
  }
];

let matched = null;
for (const policy of POLICY) {
  for (const kw of policy.keywords) {
    if (t.includes(kw)) { matched = policy; break; }
  }
  if (matched) break;
}

if (!matched) {
  matched = {
    key: 'UNCLASSIFIED',
    verdict: 'CONDITIONAL',
    class: 'UNCLASSIFIED_PROPOSAL',
    reason: 'Proposal could not be deterministically classified against any known decision type. Manual review required before execution is authorized.',
    constraints_failed: ['requires_classification']
  };
}

return [{ json: { proposal, classification: matched } }];

const { proposal, classification } = $input.first().json;
const ts = new Date().toISOString();
const traceId = 'zti-' + Date.now().toString(36).toUpperCase();

// Deterministic FNV-1a hash
function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
}

const base = `${traceId}|${ts}|${classification.class}|${proposal}`;
const h1 = fnv1a(base);
const h2 = fnv1a(h1 + ts);
const integrityHash = 'sha256:' + h1 + h2;

const STEPS = [
  { name: 'parse_proposal',       result: 'PASS' },
  { name: 'registry_lookup',      result: 'PASS' },
  { name: 'pattern_classification', result: classification.verdict === 'BLOCK' ? 'MATCH_BLOCKED' : classification.verdict === 'CONDITIONAL' ? 'MATCH_CONDITIONAL' : 'MATCH_ALLOWED' },
  { name: 'constraint_validation', result: classification.constraints_failed.length > 0 ? 'FAILED' : 'PASS' },
  { name: 'explainability_artifact', result: 'PASS' },
  { name: 'integrity_seal',       result: 'PASS' }
];

const artifact = {
  trace_id: traceId,
  timestamp: ts,
  proposal: proposal.substring(0, 200),
  classification: classification.class,
  verdict: classification.verdict,
  reason: classification.reason,
  constraints_failed: classification.constraints_failed,
  pipeline: STEPS,
  integrity_hash: integrityHash,
  sealed: true
};

return [{ json: artifact }];
